import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'flowise-chatbot',
});

const sessionId = `chat-${userId}-${Date.now()}`;
const trace = await vex.trace.start({
  name: 'flowise-chatbot-session',
  sessionId,
  metadata: { userId, intent: 'conversation' },
});

async function instrumentNode<T>(nodeName: string, input: any, fn: () => Promise<T>): Promise<T> {
  const span = await trace.span.start({ name: `flowise-${nodeName}` });

  try {
    const output = await fn();

    // Validate intermediate output
    await vex.verify({
      traceId: trace.id,
      spanId: span.id,
      data: output,
      checks: [
        'json_schema',
        { hallucination: { threshold: 0.2 } },
        'pii_detection'
      ]
    });

    return output;
  } finally {
    await span.end();
  }
}

async function validateRetrieval(docs: Document[], query: string): Promise<boolean> {
  const results = await vex.verify({
    data: { query, docs: docs.map(d => d.pageContent) },
    checks: [
      {
        type: 'rag_relevance',
        threshold: 0.75,
        metadata: { min_docs: 3 }
      }
    ]
  });

  return results.passed && results.metrics.relevance.score > 0.75;
}

async function guardResponse(response: string, context: Context): Promise<VerifiedResponse> {
  const verification = await vex.verify({
    data: { response, context },
    checks: [
      'safety_filter',
      'pii_protection',
      { hallucination: { threshold: 0.1 } },
      'response_accuracy',
      { coherence: { sessionId: trace.sessionId } }
    ]
  });

  return {
    response: verification.passed ? response : 'I need to verify that information...',
    safe: verification.passed,
    issues: verification.failures
  };
}

