// flowise.config.ts

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

// Add to Flowise chatflow callbacks
export const vexCallback = {
  handleLLMStart: async (params: any) => {
    const trace = await vex.trace.start({ name: 'llm-call' });
    return { traceId: trace.id };
  },

  handleLLMEnd: async (output: any, traceId: string) => {
    await vex.verify({
      traceId,
      data: output.generations[0][0].text,
      checks: ['hallucination', 'safety_filter']
    });
  },

  handleRetrieval: async (docs: any[]) => {
    return vex.verify({
      data: docs,
      checks: [{ type: 'rag_relevance', threshold: 0.75 }]
    });
  }
};

// In Flowise Custom Tool Node
class VexInstrumentedTool extends BaseTool {
  async _call(input: string): Promise<string> {
    const span = await this.trace.span.start({ name: 'custom-tool' });

    try {
      const result = await this.toolLogic(input);

      // Schema validation
      const valid = await vex.verify({
        spanId: span.id,
        data: result,
        checks: ['json_schema']
      });

      if (!valid.passed) {
        throw new Error('Tool output validation failed');
      }

      return result;
    } catch (error) {
      await vex.span.update(span.id, { error: error.message });
      throw error;
    } finally {
      await span.end();
    }
  }
}

async function validateMemoryContext(history: ChatMessage[], currentInput: string) {
  const contextCheck = await vex.verify({
    data: {
      history: history.slice(-5), // Last 5 exchanges
      current: currentInput
    },
    checks: [
      {
        type: 'conversation_coherence',
        params: {
          max_topic_drift: 0.3,
          session_timeout: 3600
        }
      },
      'pii_detection'
    ]
  });

  if (!contextCheck.passed) {
    // Reset or summarize memory
    return await summarizeConversation(history);
  }

  return history;
}
